'use client';
import { useRouter, usePathname, useSearchParams, useParams as useNextParams } from 'next/navigation';
import NextLink from 'next/link';
import { useEffect } from 'react';

export const Link = ({ to, children, ...props }) => {
  // Handle empty to
  const href = to || '#';
  return <NextLink href={href} {...props}>{children}</NextLink>;
};

export const useNavigate = () => {
  const router = useRouter();
  // Mimic navigate(path, { replace: true }) if needed, but basic string is common
  return (path) => router.push(path);
};

export const useLocation = () => {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  return { 
    pathname, 
    search: searchParams ? `?${searchParams.toString()}` : '',
    hash: '' // Next.js doesn't easily expose hash in generic hook
  };
};

export const useParams = useNextParams;

export const Navigate = ({ to }) => {
  const router = useRouter();
  useEffect(() => {
    if (to) router.push(to);
  }, [to, router]);
  return null;
};
